import React from 'react'
import { Box, Button, Card, CardContent, Checkbox, Chip, Divider, FormControl, FormControlLabel, FormGroup, InputLabel, MenuItem, Select, SelectChangeEvent, Stack, TextField, Typography } from '@mui/material'
import List from '@mui/material/List'
import ListItem from '@mui/material/ListItem'
import ListItemText from '@mui/material/ListItemText'
import ListItemAvatar from '@mui/material/ListItemAvatar'
import Avatar from '@mui/material/Avatar'
import { PageContainer } from '@/components/PageContainer'
import { StatusMessage } from '@/components/StatusMessage'
import ContactMailIcon from '@mui/icons-material/ContactMail'
import WorkIcon from '@mui/icons-material/Work'
import SchoolIcon from '@mui/icons-material/School'
import BadgeIcon from '@mui/icons-material/Badge';
import { CreateProfilePayload, ProfileResult } from '@/types/profile.types'
import { CallStatus, Gender, ProfileType, SchoolData, Validator } from '@/types/api.types'
import { Schools } from '@/constants/StaticData'
import { StateData } from '@/store';
import { ApiComponentStateManager } from '@/lib/api-state';
import { ProfileServices, ProfileServicesError } from '@/api';
import { Pathname, createRedirectUrl } from '@/constants/Routes';
import { submitButtonStyle } from '@/constants/ThemeConstants';
import { logger } from '@/utils/logger';

export interface ProfileCreateProps {
    redirectUrl?: string;
}

export const ProfileCreate: React.FunctionComponent<ProfileCreateProps> = ({ redirectUrl }) => {
    const hiddenText = '[Visible to you only]'
    const visibleText = '[Visible to all members]'
    const [formData, setFormData] = React.useState<CreateProfilePayload>({
        name: '',
        email: '',
        gender: Gender.Male,
        isContactInfoVisible: false,
        phone: '',
        location: '',
        latitude: 0,
        longitude: 0,
        profileType: ProfileType.Alumni,
        entryYear: 0,
        entryClass: 0,
        exitYear: 0,
        exitClass: 0,
        firstJnvId: 0,
        otherJnvIds: [],
        isHigherEducationInfoVisible: false,
        isStudying: false,
        university: '',
        degree: '',
        isEmploymentInfoVisible: false,
        isWorking: false,
        organisation: '',
        jobTitle: '',
    } as CreateProfilePayload);
    const [isFormValid, setIsFormValid] = React.useState<boolean>(false);
    const [isFormTouched, setIsFormTouched] = React.useState<boolean>(false);
    const [isSubmitted, setIsSubmitted] = React.useState<boolean>(false);
    const [selectedSchools, setSelectedSchools] = React.useState<SchoolData[]>([]);
    const [profile, setProfile] = React.useState<StateData<ProfileResult>>({} as StateData<ProfileResult>);

    const handleSecondarySchoolIdsRemove = (schoolToDelete: SchoolData) => {
        const newSecondarySchoolIds = selectedSchools.filter((selectedSchools) => selectedSchools.UniqueId !== schoolToDelete.UniqueId);
        setSelectedSchools(newSecondarySchoolIds);
        const uniqueIds = newSecondarySchoolIds.map((school) => school.UniqueId);
        setFormData({ ...formData, otherJnvIds: uniqueIds });
        validateForm();
    };

    const handleSecondarySchoolIdsAdd = (schoolToAdd: SchoolData) => {
        if (!selectedSchools.find((selectedSchools) => selectedSchools.UniqueId === schoolToAdd.UniqueId)) {
            const newSecondarySchoolIds = [...selectedSchools, schoolToAdd];
            setSelectedSchools(newSecondarySchoolIds);
            const uniqueIds = newSecondarySchoolIds.map((school) => school.UniqueId);
            setFormData({ ...formData, otherJnvIds: uniqueIds });
        }
        validateForm();
    };

    // React.useEffect(() => {
    //     GetEmptyProfileManager(setProfile);
    // }, []);

    // Validate the Update Profile Payload
    const validateForm = React.useCallback((): boolean => {

        // Base validation for all profile types
        const isBasicInfoValid: boolean = Validator.IsText(formData.name || '')
            && Validator.IsText(formData.gender || '')
            && Validator.IsEmail(formData.email || '')
            && Validator.IsPhone(formData.phone || '')
            && Validator.IsText(formData.location || '')
            && (formData.entryYear) > 0
            && (formData.firstJnvId) > 0;

        let isValid: boolean = false;

        if (formData.profileType === ProfileType.Student) {
            isValid = isBasicInfoValid
                && (formData.entryClass) > 0
                && (formData.entryYear) > 0
                && (formData.exitClass) === 0
                && (formData.exitYear) === 0;
        }
        else if (formData.profileType === ProfileType.Staff) {
            isValid = isBasicInfoValid
                && Validator.IsText(formData.organisation || '')
                && Validator.IsText(formData.jobTitle || '')
                && (formData.exitYear) === 0; // Staff should have exitYear as 0
        }
        else if (formData.profileType === ProfileType.Alumni) {
            isValid = isBasicInfoValid
                && (formData.entryClass) > 0
                && (formData.entryYear) > 0
                && (formData.exitClass) > (formData.entryClass)
                && (formData.exitYear) > (formData.entryYear)
                && Validator.IsText(formData.university || '')
                && Validator.IsText(formData.degree || '');
        }
        else if (formData.profileType === ProfileType.ExStaff) {
            isValid = isBasicInfoValid
                && (formData.entryYear) > 0
                && (formData.exitYear) > (formData.entryYear)
                && Validator.IsText(formData.university || '')
                && Validator.IsText(formData.degree || '');
        }
        else {
            isValid = isBasicInfoValid;
        }

        logger.debug('ProfileCreate', 'Validation Debug', {
            profileType: formData.profileType,
            entryYear: formData.entryYear,
            exitYear: formData.exitYear,
            entryClass: formData.entryClass,
            exitClass: formData.exitClass,
            isBasicInfoValid,
            isValid
        });

        setIsFormValid(isValid);
        return isValid;
    }, [formData]);

    // Validate form whenever formData changes
    React.useEffect(() => {
        validateForm();
    }, [validateForm]);

    const handleProfileTypeChange = (e: SelectChangeEvent<ProfileType>) => {
        if (e.target.value === ProfileType.Student) {
            setFormData({ ...formData, profileType: e.target.value, isStudying: true, isWorking: false, exitClass: 0, exitYear: 0, university: '', degree: '', organisation: '', jobTitle: '' });
        }
        else if (e.target.value === ProfileType.Staff) {
            setFormData({ ...formData, profileType: e.target.value, isStudying: false, isWorking: true, exitClass: 0, exitYear: 0, organisation: 'Navodaya Vidyala Samiti' });
        }
        else {
            setFormData({ ...formData, profileType: e.target.value as ProfileType });
        }
    }

    // Handle Form Submit
    const handleFormSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setIsFormTouched(true);
        if (validateForm()) {            
            ApiComponentStateManager(ProfileServices.CreateProfile(formData), setProfile);
        }
    }

    // Watch for successful profile creation
    React.useEffect(() => {
        if (profile.status === CallStatus.Success && profile.data?.id) {
            setIsSubmitted(true);
        }
    }, [profile.status, profile.data]);

    return (
        <PageContainer
            icon={<BadgeIcon color="primary" />}
            title="Create profile"
            subtitle="Set up your alumni profile to access the network."
        >
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                {!isSubmitted ? (
                    <form onSubmit={handleFormSubmit} onChange={() => { setIsFormTouched(true); validateForm(); }}>
                        <List>
                            <ListItem>
                                <ListItemAvatar>
                                    <Avatar>
                                        <BadgeIcon />
                                    </Avatar>
                                </ListItemAvatar>
                                <ListItemText primary="Navodaya Info" secondary={visibleText} />
                            </ListItem>
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <TextField
                                    label="Name"
                                    required
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    error={isFormTouched && !!formData.name && formData.name.length < 3}
                                    value={formData.name}
                                />
                                <FormControl>
                                    <InputLabel id="gender" >Gender</InputLabel>
                                    <Select
                                        labelId="gender"
                                        id="gender-select"
                                        value={formData.gender}
                                        label="Gender"
                                        required
                                        onChange={(e) => { setFormData({ ...formData, gender: e.target.value }); validateForm(); }}
                                    >
                                        <MenuItem selected disabled value="">Select</MenuItem>
                                        {Object.values(Gender).map((genderOption) => (
                                            <MenuItem key={genderOption} value={genderOption}>{genderOption}</MenuItem>
                                        ))}
                                    </Select>
                                </FormControl>
                                <FormControl>
                                    <InputLabel id="profileType" >Profile Type</InputLabel>
                                    <Select
                                        labelId="profileType"
                                        id="profileType-select"
                                        value={formData.profileType}
                                        label="Profile type"
                                        required
                                        onChange={(e) => { handleProfileTypeChange(e); validateForm(); }}
                                    >
                                        <MenuItem disabled value="">Select</MenuItem>
                                        <MenuItem key={ProfileType.Alumni} value={ProfileType.Alumni}>JNV Alumni</MenuItem>
                                        <MenuItem key={ProfileType.Student} value={ProfileType.Student}>Current JNV Student</MenuItem>
                                        <MenuItem key={ProfileType.ExStaff} value={ProfileType.ExStaff}>Former JNV Staff</MenuItem>
                                        <MenuItem key={ProfileType.Staff} value={ProfileType.Staff}>Current JNV Staff</MenuItem>
                                    </Select>
                                </FormControl>
                                <FormControl>
                                    <InputLabel id="entryJNV" >Entry JNV</InputLabel>
                                    <Select
                                        labelId="entryJNV"
                                        id="entryJNV-select"
                                        value={formData.firstJnvId.toString()}
                                        defaultValue=""
                                        label="Entry JNV"
                                        required
                                        error={isFormTouched && formData.firstJnvId === 0}
                                        onChange={(e) => { setFormData({ ...formData, firstJnvId: parseInt(e.target.value) }); validateForm(); }}
                                    >
                                        <MenuItem disabled value="0">
                                            Select
                                        </MenuItem>
                                        {Schools.map((school) => (
                                            <MenuItem key={school.UniqueId} value={school.UniqueId.toString()}>[{school.StatePrefix}] JNV {school.SchoolName}</MenuItem>
                                        ))}
                                    </Select>
                                </FormControl>
                                <FormControl>
                                    <InputLabel id="otherJNVs" >Other JNV</InputLabel>
                                    <Select
                                        labelId="otherJNVs"
                                        id="otherJNVs-select"
                                        label="Other JNVs"
                                        value="Add other JNVs attended"
                                        onChange={(e) => { handleSecondarySchoolIdsAdd(Schools.find((school) => school.UniqueId === parseInt(e.target.value)) as SchoolData); validateForm(); }}
                                    >
                                        <MenuItem disabled value="Add other JNVs attended">Add other JNVs attended</MenuItem>
                                        {Schools.filter((school) => !selectedSchools.find((selectedSchool) => selectedSchool.UniqueId === school.UniqueId)).map((school) => (
                                            <MenuItem key={school.UniqueId} value={school.UniqueId}>[{school.StatePrefix}] JNV {school.SchoolName}</MenuItem>
                                        ))}
                                    </Select>
                                </FormControl>
                                <Stack
                                    sx={{
                                        display: 'flex',
                                        justifyContent: 'left',
                                        flexWrap: 'wrap',
                                    }}
                                >
                                    {selectedSchools.map((school) => {
                                        return (
                                            <ListItem key={school.UniqueId}>
                                                <Chip
                                                    label={`${school.StatePrefix} - ${school.SchoolName}`}
                                                    onDelete={() => handleSecondarySchoolIdsRemove(school)}
                                                />
                                            </ListItem>
                                        );
                                    })}
                                </Stack>
                                {
                                    (formData.profileType === ProfileType.Student || formData.profileType === ProfileType.Alumni) &&
                                    (
                                        <FormControl>
                                            <InputLabel id="entryClass">Entry class</InputLabel>
                                            <Select
                                                labelId="entryClass"
                                                id="entryClass-select"
                                                value={formData.entryClass.toString()}
                                                label="Entry class"
                                                required
                                                error={isFormTouched && formData.entryClass === 0}
                                                onChange={(e) => { 
                                                    setFormData({ ...formData, entryClass: parseInt(e.target.value) }); 
                                                }}
                                            >
                                                <MenuItem disabled value="0">Select</MenuItem>
                                                {
                                                    Array.from(Array(12 - 6 + 1).keys()).map((i) => i + 6).map((entryClassOption) => (
                                                        <MenuItem key={entryClassOption} value={entryClassOption}>{entryClassOption}</MenuItem>
                                                    ))
                                                }
                                            </Select>
                                        </FormControl>
                                    )
                                }
                                {
                                    formData.profileType === ProfileType.Alumni &&
                                    (
                                        <FormControl>
                                            <InputLabel id="exitClass">Exit class</InputLabel>
                                            <Select
                                                labelId="exitClass"
                                                id="exitClass-select"
                                                value={formData.exitClass.toString()}
                                                label="Exit class"
                                                required
                                                error={isFormTouched && formData.profileType === ProfileType.Alumni && (formData.exitClass === 0 || formData.exitClass <= formData.entryClass)}
                                                onChange={(e) => { 
                                                    setFormData({ ...formData, exitClass: parseInt(e.target.value) }); 
                                                }}
                                            >
                                                <MenuItem disabled value="0">Select</MenuItem>
                                                {
                                                    Array.from(Array(12 - 6 + 1).keys()).map((i) => i + 6).map((exitClassOption) => (
                                                        <MenuItem key={exitClassOption} value={exitClassOption}>{exitClassOption}</MenuItem>
                                                    ))
                                                }
                                            </Select>
                                        </FormControl>
                                    )
                                }

                                <FormControl>
                                    <InputLabel id="entryYear">Entry year</InputLabel>
                                    <Select
                                        labelId="entryYear"
                                        id="entryYear-select"
                                        value={formData.entryYear?.toString()}
                                        label="Entry year"
                                        required
                                        error={isFormTouched && formData.entryYear === 0}
                                        onChange={(e) => { 
                                            const newEntryYear = parseInt(e.target.value);
                                            setFormData({ ...formData, entryYear: newEntryYear }); 
                                        }}
                                    >
                                        <MenuItem disabled value="0">Select</MenuItem>
                                        {
                                            Array.from(Array((new Date()).getFullYear() - 1985 + 1).keys()).map((i) => i + 1985).map((entryYearOption) => (
                                                <MenuItem key={entryYearOption} value={entryYearOption}>{entryYearOption}</MenuItem>
                                            ))
                                        }
                                    </Select>
                                </FormControl>

                                {
                                    (formData.profileType !== ProfileType.Student && formData.profileType !== ProfileType.Staff) &&
                                    (
                                        <FormControl>
                                            <InputLabel id="exitYear">Exit year</InputLabel>
                                            <Select
                                                labelId="exitYear"
                                                id="exitYear-select"
                                                value={formData.exitYear?.toString()}
                                                label="Exit year"
                                                error={isFormTouched && 
                                                    ((formData.profileType === ProfileType.Alumni || formData.profileType === ProfileType.ExStaff) && 
                                                     (formData.exitYear === 0 || formData.exitYear <= formData.entryYear))}
                                                required
                                                onChange={(e) => { 
                                                    const newExitYear = parseInt(e.target.value);
                                                    setFormData({ ...formData, exitYear: newExitYear });
                                                }}
                                            >
                                                <MenuItem disabled value="0">Select</MenuItem>
                                                {
                                                    Array.from(Array((new Date()).getFullYear() - 1985 + 1).keys()).map((i) => i + 1985).map((exitYearOption) => (
                                                        <MenuItem key={exitYearOption} value={exitYearOption}>{exitYearOption}</MenuItem>
                                                    ))
                                                }
                                            </Select>
                                        </FormControl>
                                    )
                                }
                            </Stack>
                            <Divider />
                            <ListItem>
                                <ListItemAvatar>
                                    <Avatar>
                                        <ContactMailIcon />
                                    </Avatar>
                                </ListItemAvatar>
                                <ListItemText
                                    primary='Contact Info'
                                    secondary={
                                        formData.isContactInfoVisible ? visibleText : hiddenText
                                    }
                                />
                            </ListItem>
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <FormControlLabel
                                    control={<Checkbox checked={formData.isContactInfoVisible}
                                        onChange={(e) => { setFormData({ ...formData, isContactInfoVisible: e.target.checked }); validateForm(); }} />}
                                    label="Visible to members" />
                                <TextField
                                    label="Email"
                                    onChange={(e) => { setFormData({ ...formData, email: e.target.value }); validateForm(); }}
                                    error={isFormTouched && !Validator.IsEmail(formData.email)}
                                    value={formData.email}
                                />
                                <TextField
                                    label="Phone"
                                    placeholder="Format: 9876543210 or +123-9876543210"
                                    onChange={(e) => { setFormData({ ...formData, phone: e.target.value }); validateForm(); }}
                                    error={isFormTouched && !Validator.IsPhone(formData.phone)}
                                    value={formData.phone || ''}
                                />
                                <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.75rem', mt: 0.5, ml: 1.75 }}>
                                    Indian: 10 digits (9876543210)
                                    <br />
                                    Abroad: +countrycode-number (+123-9876543210)
                                </Typography>
                                <TextField
                                    label="Location"
                                    onChange={(e) => { setFormData({ ...formData, location: e.target.value }); validateForm(); }}
                                    error={isFormTouched && !Validator.IsText(formData.location)}
                                    value={formData.location || ''}
                                />
                            </Stack>
                            {
                                formData.profileType && formData.profileType !== ProfileType.Student && (
                                    <>
                                        <Divider />
                                        <ListItem>
                                            <ListItemAvatar>
                                                <Avatar>
                                                    <SchoolIcon />
                                                </Avatar>
                                            </ListItemAvatar>
                                            <ListItemText
                                                primary='Highest Educational Info'
                                                secondary={
                                                    formData.isHigherEducationInfoVisible
                                                        ? visibleText
                                                        : hiddenText
                                                }
                                            />
                                        </ListItem>
                                        <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                            <FormGroup>
                                                <FormControlLabel
                                                    control={<Checkbox checked={formData.isHigherEducationInfoVisible}
                                                        onChange={(e) => { setFormData({ ...formData, isHigherEducationInfoVisible: e.target.checked }); validateForm(); }} />}
                                                    label="Visible to members"
                                                />
                                                <FormControlLabel
                                                    control={<Checkbox checked={formData.isStudying}
                                                        onChange={(e) => { setFormData({ ...formData, isStudying: e.target.checked }); validateForm(); }} />}
                                                    label="Currently studying" />
                                            </FormGroup>
                                            <TextField
                                                label="University/College/School"
                                                onChange={(e) => { setFormData({ ...formData, university: e.target.value }); validateForm(); }}
                                                error={isFormTouched && (formData.profileType === ProfileType.Alumni || formData.profileType === ProfileType.ExStaff) && !Validator.IsText(formData.university)}
                                                value={formData.university}
                                            />
                                            <TextField
                                                label="Degree/Level"
                                                onChange={(e) => { setFormData({ ...formData, degree: e.target.value }); validateForm(); }}
                                                error={isFormTouched && (formData.profileType === ProfileType.Alumni || formData.profileType === ProfileType.ExStaff) && !Validator.IsText(formData.degree)}
                                                value={formData.degree}
                                            />
                                        </Stack>
                                    </>
                                )
                            }
                            {
                                formData.profileType && formData.profileType !== ProfileType.Student &&
                                (
                                    <>
                                        <Divider />
                                        <ListItem>
                                            <ListItemAvatar>
                                                <Avatar>
                                                    <WorkIcon />
                                                </Avatar>
                                            </ListItemAvatar>
                                            <ListItemText
                                                primary='Latest Employment Info'
                                                secondary={
                                                    formData.isEmploymentInfoVisible ? visibleText : hiddenText
                                                }
                                            />
                                        </ListItem>
                                        <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                            <FormGroup>
                                                <FormControlLabel
                                                    control={<Checkbox checked={formData.isEmploymentInfoVisible}
                                                        onChange={(e) => { setFormData({ ...formData, isEmploymentInfoVisible: e.target.checked }); validateForm(); }} />}
                                                    label="Visible to members"
                                                />
                                                <FormControlLabel
                                                    control={<Checkbox checked={formData.isWorking}
                                                        onChange={(e) => { setFormData({ ...formData, isWorking: e.target.checked }); validateForm(); }} />}
                                                    label="Currently working" />
                                            </FormGroup>
                                            <TextField
                                                label="organisation"
                                                onChange={(e) => setFormData({ ...formData, organisation: e.target.value })}
                                                error={isFormTouched && (formData.profileType === ProfileType.Staff || formData.isWorking) && !Validator.IsText(formData.organisation)}
                                                value={formData.organisation}
                                            />
                                            <TextField
                                                label="Job Title"
                                                onChange={(e) => setFormData({ ...formData, jobTitle: e.target.value })}
                                                error={isFormTouched && (formData.profileType === ProfileType.Staff || formData.isWorking) && !Validator.IsText(formData.jobTitle)}
                                                value={formData.jobTitle}
                                            />
                                        </Stack>
                                    </>
                                )
                            }
                            <Divider />
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <Button style={submitButtonStyle} disabled={!isFormValid} variant="contained" type="submit">Submit</Button>
                                <StatusMessage
                                    currentStatus={profile.status}
                                    notStartedMessage="Please crosscheck your email before you submit."
                                    successMessage="Profile created successfully! Redirecting to login..."
                                    failureMessage={ProfileServicesError.CreateProfileError(profile.httpStatus)}
                                    correlationId={profile.correlationId}
                                />
                            </Stack>
                        </List>
                    </form>
                ) : (
                    <Stack direction="column" spacing={3} sx={{ alignItems: 'center', padding: 3, textAlign: 'center' }}>
                        <Box>
                            <Typography variant="h6" sx={{ fontWeight: 500, mb: 2 }}>
                                Welcome <strong>{profile.data.name}</strong>! 🎉
                            </Typography>
                            <Typography variant="body1" sx={{ color: 'text.secondary', mb: 3 }}>
                                {redirectUrl && redirectUrl.includes('/events') ? (
                                    <>
                                        One last step is pending...<br />
                                        <strong>Please login to complete your event registration.</strong>
                                    </>
                                ) : (
                                    'Your profile has been successfully created.'
                                )}
                            </Typography>
                        </Box>
                        <Button 
                            variant="contained" 
                            size="medium"
                            href={redirectUrl && redirectUrl !== Pathname.Root ? createRedirectUrl(Pathname.Login, redirectUrl) : Pathname.Login}
                            sx={{ minWidth: 150 }}
                        >
                            Continue to Login
                        </Button>
                    </Stack>
                )}
                    </CardContent>
                </Card>
        </PageContainer>
    )
}

