import React, { Suspense } from "react";
import { useSearch } from '@tanstack/react-router';
import { ProfileCreate } from "@/pages/profile/ProfileCreate";

const RegisterContent: React.FunctionComponent = () => {
  const search = useSearch({ strict: false }) as Record<string, string>;
  const [redirectUrl, setRedirectUrl] = React.useState<string>('');

  // Handle redirect URL after component mounts to avoid hydration issues
  React.useEffect(() => {
    const redirect = search?.redirect || '';
    setRedirectUrl(redirect);
  }, [search]);

  return (
    <div style={{ display: 'flex', justifyContent: 'center' }}>
      <ProfileCreate redirectUrl={redirectUrl} />
    </div>
  );
};

export const Register: React.FunctionComponent = () => {
  return (
    <Suspense fallback={<div style={{ display: 'flex', justifyContent: 'center', padding: '20px' }}>Loading...</div>}>
      <RegisterContent />
    </Suspense>
  );
};

